'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Returns the index of the last truthy element in a single-precision floating-point strided array.
*
* ## Notes
*
* -   If unable to find a truthy element, the function returns `-1`.
* -   The function explicitly treats `NaN` values as falsy.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Float32Array} x - input array
* @param {integer} strideX - stride length
* @returns {integer} index
*
* @example
* import Float32Array from '@stdlib/array-float32';
*
* var x = new Float32Array( [ 0.0, 0.0, 3.0, 0.0, 4.0, 0.0, -1.0, 3.0 ] );
*
* var idx = slastIndexOfTruthy( x.length, x, 1 );
* // returns 7
*/
function slastIndexOfTruthy( N, x, strideX ) {
	return ndarray( N, x, strideX, stride2offset( N, strideX ) );
}


// EXPORTS //

export default slastIndexOfTruthy;
