'use strict';

/**
* Convert a strided array to a min-heap.
*
* @module @stdlib/blas-ext-base-gminheapify
*
* @example
* import gminheapify from '@stdlib/blas-ext-base-gminheapify';
*
* var x = [ 7.0, 5.0, 3.0, 1.0, 9.0 ];
*
* gminheapify( 5, x, 1 );
* // x => [ 1.0, 5.0, 3.0, 7.0, 9.0 ]
*
* @example
* import gminheapify from '@stdlib/blas-ext-base-gminheapify';
*
* var x = [ 7.0, 5.0, 3.0, 1.0, 9.0 ];
*
* gminheapify.ndarray( 5, x, 1, 0 );
* // x => [ 1.0, 5.0, 3.0, 7.0, 9.0 ]
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
