'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Multiplies each element in a single-precision complex floating-point strided array by a scalar constant and adds a scalar constant to each result.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Complex64} alpha - first scalar constant
* @param {Complex64} beta - second scalar constant
* @param {Complex64Array} x - input array
* @param {integer} strideX - stride length
* @returns {Complex64Array} input array
*
* @example
* import Complex64Array from '@stdlib/array-complex64';
* import Complex64 from '@stdlib/complex-float32-ctor';
*
* var x = new Complex64Array( [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ] );
*
* var alpha = new Complex64( 2.0, 0.0 );
* var beta = new Complex64( 1.0, 0.0 );
*
* caxpb( x.length, alpha, beta, x, 1 );
* // x => <Complex64Array>[ -3.0, 2.0, 7.0, -10.0, 9.0, 0.0, -1.0, -6.0 ]
*/
function caxpb( N, alpha, beta, x, strideX ) {
	return ndarray( N, alpha, beta, x, strideX, stride2offset( N, strideX ) );
}


// EXPORTS //

export default caxpb;
