'use strict';

// MAIN //

/**
* Returns the index of the first falsy element in a single-precision floating-point strided array using alternative indexing semantics.
*
* ## Notes
*
* -   If unable to find a falsy element, the function returns `-1`.
* -   The function explicitly treats `NaN` values as falsy.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Float32Array} x - input array
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {integer} index
*
* @example
* import Float32Array from '@stdlib/array-float32';
*
* var x = new Float32Array( [ 1.0, 2.0, 0.0, 3.0, 4.0, 5.0, 6.0, 7.0 ] );
*
* var idx = sindexOfFalsy( x.length, x, 1, 0 );
* // returns 2
*/
function sindexOfFalsy( N, x, strideX, offsetX ) {
	var ix;
	var i;

	if ( N <= 0 ) {
		return -1;
	}
	ix = offsetX;
	for ( i = 0; i < N; i++ ) {
		if ( !x[ ix ] ) {
			return i;
		}
		ix += strideX;
	}
	return -1;
}


// EXPORTS //

export default sindexOfFalsy;
