'use strict';

// MODULES //

import { ndarray as gindexOfTruthy } from '@stdlib/blas-ext-base-gindex-of-truthy';


// MAIN //

/**
* Returns the index of the last truthy element in a strided array using alternative indexing semantics.
*
* ## Notes
*
* -   If unable to find a truthy element, the function returns `-1`.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Collection} x - input array
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {integer} index
*
* @example
* var x = [ 0.0, 0.0, 3.0, 0.0, 4.0, 0.0, -1.0, 3.0 ];
*
* var idx = glastIndexOfTruthy( x.length, x, 1, 0 );
* // returns 7
*/
function glastIndexOfTruthy( N, x, strideX, offsetX ) {
	var idx;

	if ( N <= 0 ) {
		return -1;
	}
	// Reverse the iteration order by flipping the stride and adjusting the offset:
	offsetX += ( N-1 ) * strideX;
	strideX *= -1;

	// Find the index of the first truthy element in the reversed "view":
	idx = gindexOfTruthy( N, x, strideX, offsetX );
	if ( idx < 0 ) {
		return idx;
	}
	// Convert the index from reversed "view" to an index in the original "view":
	return N - 1 - idx;
}


// EXPORTS //

export default glastIndexOfTruthy;
